     2→pragma solidity 0.8.26;
     3→
     4→import {ITypeAndVersion} from "@chainlink/contracts/src/v0.8/shared/interfaces/ITypeAndVersion.sol";
     5→import {IAuctionCallback} from "src/interfaces/IAuctionCallback.sol";
     6→import {IBaseAuction} from "src/interfaces/IBaseAuction.sol";
     7→import {IFeeAggregator} from "src/interfaces/IFeeAggregator.sol";
     8→
     9→import {Caller} from "src/Caller.sol";
    10→import {PriceManager} from "src/PriceManager.sol";
    11→import {Common} from "src/libraries/Common.sol";
    12→import {Errors} from "src/libraries/Errors.sol";
    13→import {Roles} from "src/libraries/Roles.sol";
    14→
    15→import {IERC20Metadata} from "@openzeppelin/contracts/interfaces/IERC20Metadata.sol";
    16→import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
    17→import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
    18→import {IERC165} from "@openzeppelin/contracts/utils/introspection/IERC165.sol";
    19→import {EnumerableSet} from "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
    20→import {FixedPointMathLib} from "solady/src/utils/FixedPointMathLib.sol";
    21→
    22→abstract contract BaseAuction is PriceManager, ITypeAndVersion, Caller, IBaseAuction {
    23→  using EnumerableSet for EnumerableSet.AddressSet;
    24→  using FixedPointMathLib for uint256;
    25→  using SafeERC20 for IERC20;
    26→
    27→  /// @notice This event is emitted when the asset out address is set.
    28→  /// @param assetOut The address of the asset out.
    29→  event AssetOutSet(address indexed assetOut);
    30→  /// @notice This event is emitted when the asset out receiver address is set.
    31→  /// @param assetOutReceiver The address of the asset out receiver.
    32→  event AssetOutReceiverSet(address indexed assetOutReceiver);
    33→  /// @notice This event is emitted when the parameters of an asset are updated.
    34→  /// @param asset The address of the asset.
    35→  /// @param params The updated asset parameters.
    36→  event AssetParamsUpdated(address indexed asset, AssetParams params);
    37→  /// @notice This event is emitted when the parameters of an asset are removed.
    38→  /// @param asset The address of the asset.
    39→  event AssetParamsRemoved(address indexed asset);
    40→  /// @notice This event is emitted when a new fee aggregator receiver is set
    41→  /// @param feeAggregator The address of the fee aggregator
    42→  event FeeAggregatorSet(address indexed feeAggregator);
    43→  /// @notice This event is emitted when the minimum bid USD value is set.
    44→  /// @param minBidUsdValue The minimum bid USD value in 18 decimals.
    45→  event MinBidUsdValueSet(uint88 indexed minBidUsdValue);
    46→  /// @notice This event is emitted when the maximum discount basis points is set.
    47→  /// @param minPriceMultiplier The maximum discount basis points.
    48→  event MinPriceMultiplierSet(uint64 indexed minPriceMultiplier);
    49→  /// @notice This event is emitted when an auction is started for an asset.
    50→  /// @param asset The address of the asset for which the auction is started.
    51→  event AuctionStarted(address indexed asset);
    52→  /// @notice This event is emitted when an auction is ended for an asset.
    53→  /// @param asset The address of the asset for which the auction is ended.
    54→  event AuctionEnded(address indexed asset);
    55→  /// @notice This event is emitted when an auction is partially settled for an asset.
    56→  /// @param bidder The address of the auction bidder.
    57→  /// @param assetIn The address of the asset being auctioned.
    58→  /// @param amountIn The amount of asset being auctioned.
    59→  /// @param amountOut The amount of asset out received.
    60→  event AuctionBidSettled(address indexed bidder, address indexed assetIn, uint256 amountIn, uint256 amountOut);
    61→
    62→  /// @notice This error is thrown when trying to access asset parameters that are not set.
    63→  /// @param asset The asset with unset parameters.
    64→  error AssetParamsNotSet(address asset);
    65→  /// @notice This error is thrown when trying to set an ending price multiplier lower than the minPriceMultiplier.
    66→  /// @param asset The asset with invalid decay rate.
    67→  /// @param endingPriceMultiplier The ending price multiplier.
    68→  /// @param minPriceMultiplier The price multiplier lower bound.
    69→  error InvalidEndingPriceMultiplier(address asset, uint256 endingPriceMultiplier, uint64 minPriceMultiplier);
    70→  /// @notice This error is thrown when the starting price multiplier is lower than the ending price multiplier.
    71→  /// @param asset The asset with invalid price multipliers.
    72→  /// @param startingPriceMultiplier The starting price multiplier.
    73→  /// @param endingPriceMultiplier The ending price multiplier.
    74→  error StartingPriceMultiplierLowerThanEndingPriceMultiplier(
    75→    address asset, uint256 startingPriceMultiplier, uint256 endingPriceMultiplier
    76→  );
    77→  /// @notice This error is thrown when the provided asset decimals do not match the actual asset decimals.
    78→  /// @param asset The address of the asset.
    79→  /// @param decimals The provided asset decimals.
    80→  /// @param expectedDecimals The actual asset decimals.
    81→  error InvalidAssetDecimals(address asset, uint8 decimals, uint8 expectedDecimals);
    82→  /// @notice This error is thrown when trying to bid a non live auction (ended, not started or non allowlisted).
    83→  /// @param asset The asset of the invalid auction.
    84→  error InvalidAuction(address asset);
    85→  /// @notice This error is thrown when trying to update auction sensitive configs during live auctions.
    86→  error LiveAuction();
    87→  /// @notice This error is thrown when the bid USD value is below the minimum auction size.
    88→  /// @param bidUsdValue The bid USD value.
    89→  /// @param minAuctionSizeUsd The minimum auction size in USD.
    90→  error BidValueTooLow(uint256 bidUsdValue, uint256 minAuctionSizeUsd);
    91→  /// @notice This error is thrown when the bid amount is higher than the available amount in the auction.
    92→  /// @param bidAmount The bid amount.
    93→  /// @param availableAmount The available amount in the auction.
    94→  error BidAmountTooHigh(uint256 bidAmount, uint256 availableAmount);
    95→  /// @notice This error is thrown when trying to call performUpkeep while the asset out parameters are missing.
    96→  error MissingAssetOutParams();
    97→  /// @notice This error is thrown when trying to force start an auction with an amount below the minimum auction size.
    98→  /// @param amountUsdValue The amount USD value.
    99→  /// @param minAuctionSizeUsd The minimum auction size in USD.
   100→  error AmountBelowMinAuctionSize(uint256 amountUsdValue, uint256 minAuctionSizeUsd);
   101→
   102→  // @notice Parameters to initialize the contract in the constructor.
   103→  // solhint-disable-next-line gas-struct-packing
   104→  struct ConstructorParams {
   105→    address admin; // ────────────────────────────────────╮
   106→    // The initial contract admin.
   107→    uint48 adminRoleTransferDelay; // ────────────────────╯ The min seconds
   108→    // before the admin address can be transferred.
   109→    uint64 minPriceMultiplier; // ────────────────────────╮ The
   110→    // auction price multiplier lower bound in basis points
   111→    //                                                    │ used for input validation of all assets configured in the
   112→    //                                                    │ contract.
   113→    address verifierProxy; // ────────────────────────────╯
   114→    // The address of the Data Streams VerifierProxy contract.
   115→    uint88 minBidUsdValue; // ────────────────────────────╮
   116→    // The minimum bid USD value in 18 decimals.
   117→    address linkToken; // ────────────────────────────────╯
   118→    // The address of the LINK token contract.
   119→    address assetOut; //                                    The asset out of all the auctions.
   120→    address assetOutReceiver; //                            The asset out receiver.
   121→    address feeAggregator; //                               The fee aggregator.
   122→    PriceManager.ApplyFeedInfoUpdateParams[] feedInfos; //  The initial feed info list.
   123→  }
   124→
   125→  /// @notice The auction parameters of an asset.
   126→  /// @dev The decay rate per second is applied linearly to the starting price multiplier.
   127→  /// @dev Asset parameters should also be configured for the asset out. Although it is not auctioned, the min auction
   128→  /// size and decimals fields are still used.
   129→  /// Example:
   130→  ///   - startingPriceMultiplier = 1.1e18 (10% premium)
   131→  ///   - endingPriceMultiplier = 0.98e18 (2% discount)
   132→  ///   - auctionDuration = 3600 (1 hour)
   133→  ///   - decayRatePerSecond = (1.1e18 - 0.98e18) / 3600 = 33333333333333 (rounded down to avoid higher
   134→  ///     discount than 2%)
   135→  struct AssetParams {
   136→    uint96 minAuctionSizeUsd; // ───────╮ The minimum swap size expressed in USD feed decimals.
   137→    uint64 startingPriceMultiplier; //  │ The starting price multiplier with 18 decimals precision.
   138→    uint64 endingPriceMultiplier; //    │ The ending price multiplier with 18 decimals precision.
   139→    uint24 auctionDuration; //          │ The duration of the auction in seconds.
   140→    uint8 decimals; //  ────────────────╯ The asset decimals.
   141→  }
   142→
   143→  /// @notice The parameters for adding or updating asset parameters.
   144→  struct ApplyAssetParamsUpdate {
   145→    address asset; // The address of the asset.
   146→    AssetParams params; // The asset parameters.
   147→  }
   148→
   149→  /// @inheritdoc ITypeAndVersion
   150→  string public constant override typeAndVersion = "Auction 1.0.0-dev";
   151→
   152→  /// @notice The auction price multiplier lower bound in 18 decimals used for input validation of all assets configured
   153→  /// in the contract - e.g. 0.98e18 represents a maximum discount of 2%.
   154→  uint64 internal immutable i_minPriceMultiplier;
   155→
   156→  /// @notice Reentrant flag.
   157→  bool internal s_entered;
   158→  /// @notice The minimum bid USD value in 18 decimals.
   159→  uint88 internal s_minBidUsdValue;
   160→  /// @notice The asset out of all the auctions.
   161→  address internal s_assetOut;
   162→  /// @notice The receiver of to tokens.
   163→  address internal s_assetOutReceiver;
   164→  /// @notice The fee aggregator
   165→  IFeeAggregator internal s_feeAggregator;
   166→
   167→  /// @notice Mapping from `from` token to its struct.
   168→  mapping(address asset => AssetParams params) internal s_assetParams;
   169→  /// @notice Mapping from `from` token to the auction start timestamp.
   170→  mapping(address asset => uint256 auctionStart) internal s_auctionStarts;
   171→
   172→  modifier whenAssetOutConfigured() {
   173→    if (s_assetParams[s_assetOut].decimals == 0) {
   174→      revert MissingAssetOutParams();
   175→    }
   176→    _;
   177→  }
   178→
   179→  constructor(
   180→    ConstructorParams memory params
   181→  )
   182→    PriceManager(params.adminRoleTransferDelay, params.admin, params.verifierProxy, params.linkToken, params.feedInfos)
   183→  {
   184→    if (params.assetOut == address(0) || params.assetOutReceiver == address(0)) {
   185→      revert Errors.InvalidZeroAddress();
   186→    }
   187→
   188→    _setMinBidUsdValue(params.minBidUsdValue);
   189→    _setAssetOut(params.assetOut);
   190→    _setAssetOutReceiver(params.assetOutReceiver);
   191→    _setFeeAggregator(params.feeAggregator);
   192→
   193→    if (params.minPriceMultiplier == 0) {
   194→      revert Errors.InvalidZeroValue();
   195→    }
   196→
   197→    i_minPriceMultiplier = params.minPriceMultiplier;
   198→
   199→    emit MinPriceMultiplierSet(params.minPriceMultiplier);
   200→  }
   201→
   202→  /// @inheritdoc IBaseAuction
   203→  /// @dev This function checks for eligible assets to start auctions and ended auctions to be closed.
   204→  /// @dev precondition - The contract must not be paused.
   205→  /// @dev precondition - The asset out must be configured.
   206→  /// For an auction to be considered eligible to start, the following conditions must be met:
   207→  ///   1) The asset out price must be valid (not stale and not zero).
   208→  ///   2) There is no live auction for the asset.
   209→  ///   3) The asset price is valid (not stale and not zero).
   210→  ///   4) The total USD value of the asset (in both the fee aggregator and the auction contract) is above the minimum
   211→  ///      auction size.
   212→  /// For an auction to be considered ended, either of the following conditions must be met:
   213→  ///   - The auction duration has elapsed since the auction start time.
   214→  ///   - The total USD value of the asset remaining in the auction contract is below the minimum auction size. This is
   215→  ///     to guard against dust attacks.
   216→  function checkUpkeep(
   217→    bytes calldata
   218→  ) external view whenNotPaused whenAssetOutConfigured returns (bool upkeepNeeded, bytes memory performData) {
   219→    address feeAggregator = address(s_feeAggregator);
   220→    address[] memory auctions = s_allowlistedAssets.values();
   221→    Common.AssetAmount[] memory eligibleAssets = new Common.AssetAmount[](auctions.length);
   222→    address[] memory endedAuctions = new address[](auctions.length);
   223→
   224→    uint256 eligibleAssetsIdx;
   225→    uint256 endedAuctionsIdx;
   226→    bool isAssetOutPriceValid;
   227→
   228→    for (uint256 i; i < auctions.length; ++i) {
   229→      address asset = auctions[i];
   230→
   231→      AssetParams memory assetParams = s_assetParams[asset];
   232→
   233→      // Skip assets without configured params.
   234→      if (assetParams.decimals == 0) {
   235→        continue;
   236→      }
   237→
   238→      (uint256 assetPrice,, bool isPriceValid) = _getAssetPrice(asset, false);
   239→
   240→      if (asset == s_assetOut) {
   241→        isAssetOutPriceValid = isPriceValid;
   242→      }
   243→
   244→      // 1) Check for live or ended auctions.
   245→      uint256 auctionStart = s_auctionStarts[asset];
   246→      if (auctionStart != 0) {
   247→        uint256 assetBalance = IERC20(asset).balanceOf(address(this));
   248→        uint256 assetBalanceUsdValue = (assetBalance * assetPrice) / (10 ** assetParams.decimals);
   249→        if (
   250→          auctionStart + assetParams.auctionDuration < block.timestamp
   251→            || (isPriceValid && assetBalanceUsdValue < assetParams.minAuctionSizeUsd)
   252→        ) {
   253→          endedAuctions[endedAuctionsIdx++] = asset;
   254→        }
   255→      } else if (isPriceValid) {
   256→        // 2) Get the current asset value in USD available for auction.
   257→        uint256 availableBalance = IERC20(asset).balanceOf(feeAggregator);
   258→        uint256 availableAssetUsdValue = (availableBalance * assetPrice) / (10 ** assetParams.decimals);
   259→
   260→        // 3) Auction asset if the asset's current USD balance is above the minimum auction size.
   261→        if (availableAssetUsdValue >= assetParams.minAuctionSizeUsd) {
   262→          // We only pass in the fee aggregator balance as the amount since its sole purpose is to pull funds from the
   263→          // fee aggregator.
   264→          eligibleAssets[eligibleAssetsIdx++] = Common.AssetAmount({asset: asset, amount: availableBalance});
   265→        }
   266→      }
   267→    }
   268→
   269→    // If the asset out price is not valid, we should not start any auctions even if there are eligible assets as bids
   270→    // would revert.
   271→    if (!isAssetOutPriceValid) {
   272→      eligibleAssetsIdx = 0;
   273→    }
   274→    if (eligibleAssetsIdx < auctions.length) {
   275→      assembly {
   276→        // update eligibleassets length.
   277→        mstore(eligibleAssets, eligibleAssetsIdx)
   278→      }
   279→    }
   280→    if (endedAuctionsIdx < auctions.length) {
   281→      assembly {
   282→        // update endedAuctionsIdx length.
   283→        mstore(endedAuctions, endedAuctionsIdx)
   284→      }
   285→    }
   286→
   287→    // Using if/else here to avoid abi.encoding empty bytes when idx = 0.
   288→    if (eligibleAssetsIdx > 0 || endedAuctionsIdx > 0) {
   289→      upkeepNeeded = true;
   290→      performData = abi.encode(eligibleAssets, endedAuctions);
   291→    }
   292→
   293→    return (upkeepNeeded, performData);
   294→  }
   295→
   296→  /// @inheritdoc IBaseAuction
   297→  /// @dev precondition - The contract must not be paused.
   298→  /// @dev precondition - The asset out must be configured.
   299→  /// @dev precondition - The caller must have the AUCTION_WORKER_ROLE.
   300→  /// @dev precondition - When starting auctions, the asset out price must be valid.
   301→  /// @dev precondition - When starting auctions, there must not be a live auction for the asset.
   302→  /// @dev precondition - Eligible assets must be configured.
   303→  /// @dev precondition - Eligible assets amounts USD values must be above the minimum auction size.
   304→  /// @dev precondition - Ended auctions must not be the asset out.
   305→  function performUpkeep(
   306→    bytes calldata performData
   307→  ) external whenNotPaused whenAssetOutConfigured onlyRole(Roles.AUCTION_WORKER_ROLE) {
   308→    (Common.AssetAmount[] memory eligibleAssets, address[] memory endedAuctions) =
   309→      abi.decode(performData, (Common.AssetAmount[], address[]));
   310→
   311→    // We should never pass a list of eligible assets with a non valid asset out price.
   312→    uint256 assetOutPrice;
   313→    address assetOut = s_assetOut;
   314→    if (eligibleAssets.length > 0) {
   315→      (assetOutPrice,,) = _getAssetPrice(assetOut, true);
   316→    }
   317→
   318→    bool hasFeeAggregator = address(s_feeAggregator) != address(this);
   319→
   320→    if (hasFeeAggregator && eligibleAssets.length > 0) {
   321→      s_feeAggregator.transferForSwap(address(this), eligibleAssets);
   322→    }
   323→
   324→    for (uint256 i; i < eligibleAssets.length; ++i) {
   325→      address asset = eligibleAssets[i].asset;
   326→
   327→      if (s_auctionStarts[asset] != 0) {
   328→        revert LiveAuction();
   329→      }
   330→
   331→      AssetParams storage assetParams = s_assetParams[asset];
   332→      uint8 assetDecimals = assetParams.decimals;
   333→
   334→      if (assetDecimals == 0) {
   335→        revert AssetParamsNotSet(asset);
   336→      }
   337→
   338→      uint256 assetPrice;
   339→      if (asset == assetOut) {
   340→        assetPrice = assetOutPrice;
   341→      } else {
   342→        (assetPrice,,) = _getAssetPrice(asset, true);
   343→      }
   344→      uint256 availableAssetUsdValue = (eligibleAssets[i].amount * assetPrice) / (10 ** assetDecimals);
   345→
   346→      if (availableAssetUsdValue < assetParams.minAuctionSizeUsd) {
