   459→
   460→  // ================================================================================================
   461→  // │                                        Configuration                                         │
   462→  // ================================================================================================
   463→
   464→  /// @notice Sets the minimum bid USD value.
   465→  /// @dev precondition - The caller must have the ASSET_ADMIN_ROLE.
   466→  function setMinBidUsdValue(
   467→    uint88 minBidUsdValue
   468→  ) external onlyRole(Roles.ASSET_ADMIN_ROLE) {
   469→    _setMinBidUsdValue(minBidUsdValue);
   470→  }
   471→
   472→  /// @dev precondition - The new minimum bid USD value must be greater than zero.
   473→  /// @dev precondition - The new minimum bid USD value must be different from the already configured one.
   474→  function _setMinBidUsdValue(
   475→    uint88 minBidUsdValue
   476→  ) private {
   477→    if (minBidUsdValue == 0) {
   478→      revert Errors.InvalidZeroValue();
   479→    }
   480→    if (s_minBidUsdValue == minBidUsdValue) {
