   485→    emit MinBidUsdValueSet(minBidUsdValue);
   486→  }
   487→
   488→  /// @notice Sets the asset out address.
   489→  /// @dev precondition - The caller must have the ASSET_ADMIN_ROLE.
   490→  /// @param assetOut The address of the asset out.
   491→  function setAssetOut(
   492→    address assetOut
   493→  ) external onlyRole(Roles.ASSET_ADMIN_ROLE) {
   494→    _setAssetOut(assetOut);
   495→  }
   496→
   497→  /// @dev precondition - There must not be a live auction.
   498→  /// @dev precondition - The asset out address must not be the zero address.
   499→  /// @dev precondition - The new asset out address must be different from the already configured asset out.
   500→  function _setAssetOut(
   501→    address assetOut
   502→  ) private {
   503→    _whenNoLiveAuctions();
   504→    if (assetOut == address(0)) {
   505→      revert Errors.InvalidZeroAddress();
   506→    }
   507→    address currentAssetOut = s_assetOut;
   508→    if (currentAssetOut == assetOut) {
   509→      revert Errors.ValueNotUpdated();
   510→    }
   511→
   512→    s_assetOut = assetOut;
   513→    delete s_assetParams[currentAssetOut];
   514→
   515→    emit AssetOutSet(assetOut);
   516→  }
   517→
