   543→    emit AssetOutReceiverSet(assetOutReceiver);
   544→  }
   545→
   546→  /// @notice Sets the fee aggregator receiver.
   547→  /// @dev precondition - The caller must have the DEFAULT_ADMIN_ROLE.
   548→  /// @param feeAggregator The address of the fee aggregator.
   549→  function setFeeAggregator(
   550→    address feeAggregator
   551→  ) external onlyRole(DEFAULT_ADMIN_ROLE) {
   552→    _setFeeAggregator(feeAggregator);
   553→  }
   554→
